class Main {
  // 1. Notice 'int' instead of 'void'
  static int calculateSum(int a, int b) {
    int sum = a + b;
    // 2. We push the answer back out
    return sum; 
  }

  public static void main(String[] args) {
    // 3. We catch the returned value in a new variable!
    int answer = calculateSum(5, 5);
    System.out.println("The answer is " + answer);
  }
}
